diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 2fb60ef11499..1df2fae401e7 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -288,20 +288,24 @@ static bool maintainNoSignedWrap(BinaryOperator &I, Value *B, Value *C) {
   if (!OBO || !OBO->hasNoSignedWrap())
     return false;

-  // We reason about Add and Sub Only.
+  // We reason about Add, Sub, and Mul.
   Instruction::BinaryOps Opcode = I.getOpcode();
-  if (Opcode != Instruction::Add && Opcode != Instruction::Sub)
-    return false;

   const APInt *BVal, *CVal;
   if (!match(B, m_APInt(BVal)) || !match(C, m_APInt(CVal)))
     return false;

   bool Overflow = false;
-  if (Opcode == Instruction::Add)
+  if (Opcode == Instruction::Add) {
     (void)BVal->sadd_ov(*CVal, Overflow);
-  else
+  } else if (Opcode == Instruction::Sub) {
     (void)BVal->ssub_ov(*CVal, Overflow);
+  } else if (Opcode == Instruction::Mul) {
+    (void)BVal->smul_ov(*CVal, Overflow);
+  } else {
+    // Conservatively return false for other opcodes.
+    return false;
+  }

   return !Overflow;
 }

